const rawData = $('Webhook').item.json.body;
const weatherData = $('HTTP Request1').item.json; 
const orders = rawData.orders;

const weatherId = weatherData.weather[0].id;
const isRaining = weatherId < 700; 
const weatherSurcharge = isRaining ? 15000 : 0;

const MAX_WEIGHT = 30; 
let trips = [];

orders.forEach(order => {
    // TỰ ĐỘNG GÁN TỌA ĐỘ GIẢ LẬP NẾU THIẾU (Tránh lỗi HTTP Request)
    if (!order.lat) order.lat = (16.06 + Math.random() * 0.02).toFixed(6);
    if (!order.lng) order.lng = (108.21 + Math.random() * 0.02).toFixed(6);

    let weight = parseFloat(order.weight);
    let isFragile = (order.tinh_chat === "FRAGILE");

    if (weight > MAX_WEIGHT) {
        trips.push({ 
            tripId: trips.length + 1, 
            vehicle: "TRUCK", 
            totalWeight: weight, 
            surcharge: (isFragile ? 10000 : 0) + weatherSurcharge,
            orders: [order] 
        });
        return;
    }

    let placed = false;
    for (let trip of trips) {
        if (trip.vehicle === "MOTORBIKE" && (trip.totalWeight + weight) <= MAX_WEIGHT) {
            trip.orders.push(order);
            trip.totalWeight += weight;
            trip.surcharge += (isFragile ? 10000 : 0);
            placed = true;
            break;
        }
    }

    if (!placed) {
        trips.push({ 
            tripId: trips.length + 1, 
            vehicle: "MOTORBIKE", 
            totalWeight: weight, 
            surcharge: (isFragile ? 10000 : 0) + weatherSurcharge,
            orders: [order] 
        });
    }
});

return trips.map(trip => ({ 
    json: { 
        tripData: trip, 
        isRaining: isRaining 
    } 
}));

// 1. Lấy dữ liệu OSRM và Dữ liệu từ Node chia đơn
const osrmResults = $('HTTP Request').all(); 
const originalTrips = $('Code in JavaScript').all().map(item => item.json);

let tongGiaoLe = 0; 
let tongGop = 0; 
let mapTrips = [];

// Thu thập tất cả đơn để tính scale tọa độ
const allOrdersFlat = originalTrips.flatMap(t => t.tripData.orders);
const hasRealCoords = allOrdersFlat.some(o => o.lat && parseFloat(o.lat) > 0);

function latLngToPixel(lat, lng, allOrders, mapW, mapH, pad) {
    const lats = allOrders.map(o => parseFloat(o.lat)).filter(v => v > 0);
    const lngs = allOrders.map(o => parseFloat(o.lng)).filter(v => v > 0);
    if (lats.length === 0) return null;
    const minLat = Math.min(...lats), maxLat = Math.max(...lats);
    const minLng = Math.min(...lngs), maxLng = Math.max(...lngs);
    const rangeX = (maxLng - minLng) || 0.001;
    const rangeY = (maxLat - minLat) || 0.001;
    const px = Math.round(pad + ((parseFloat(lng) - minLng) / rangeX) * (mapW - 2 * pad));
    const py = Math.round(pad + ((maxLat - parseFloat(lat)) / rangeY) * (mapH - 2 * pad));
    return { x: px, y: py };
}

// 2. Kế toán tính tiền chi tiết cho từng chuyến & OSRM Sắp xếp Lộ trình
const finalTrips = osrmResults.map((osrmItem, index) => {
    let t = originalTrips[index].tripData;
    let isRain = originalTrips[index].isRaining;
    let osrmData = osrmItem.json; 

    let distKm = parseFloat((osrmData.trips[0].distance / 1000).toFixed(1)); 
    let WEATHER_SURCHARGE = isRain ? 15000 : 0;

    let phiCoBan = t.vehicle === "TRUCK" ? 50000 : 15000;
    let phiKm = distKm * 5000;
    let phiRotDiem = (t.orders.length - 1) * 5000;

    let phiDeVo = 0;
    t.orders.forEach(o => {
        let isFragile = (o.tinh_chat === "FRAGILE" || o.category === "FRAGILE");
        if (isFragile) phiDeVo += 10000;
        tongGiaoLe += 15000 + (isFragile ? 10000 : 0) + (distKm * 5000) + WEATHER_SURCHARGE;
    });

    let tongChuyen = phiCoBan + phiKm + phiRotDiem + phiDeVo + WEATHER_SURCHARGE;
    tongGop += tongChuyen;

    let waypoints = osrmData.waypoints; 
    let sortableOrders = [];

    for(let i = 1; i < waypoints.length; i++) {
        sortableOrders.push({
            order: t.orders[i-1], 
            optimized_step: waypoints[i].waypoint_index
        });
    }

    sortableOrders.sort((a, b) => a.optimized_step - b.optimized_step);

    // Xây routeCoords: nếu có lat/lng thực dùng pixel; không thì không gán x/y để frontend tự layout vòng tròn
    let routeCoords = sortableOrders.map((item, idx) => {
        let pt = { 
            step: idx + 1,
            id: item.order.id || "Đơn hàng", 
            weight: item.order.weight + "kg"
        };
        if (hasRealCoords) {
            const px = latLngToPixel(item.order.lat, item.order.lng, allOrdersFlat, 280, 220, 20);
            if (px) { pt.x = px.x; pt.y = px.y; }
        }
        return pt;
    });

    mapTrips.push({
        name: t.vehicle === "TRUCK" ? `Xe Tải ${index+1}` : `Xe Máy ${index+1}`,
        color: t.vehicle === "TRUCK" ? "#f59e0b" : "#3b82f6",
        route: routeCoords
    });

    return {
        tripName: "Chuyến " + (index + 1) + (t.vehicle === "TRUCK" ? " (Xe Tải)" : " (Xe Máy)"),
        distance: distKm + " km",
        totalOrders: t.orders.length,
        breakdown_fee: {
            "Phí cơ bản": phiCoBan,
            "Phí quãng đường": phiKm,
            "Phí rớt điểm": phiRotDiem,
            "Phí dễ vỡ": phiDeVo,
            "Phí thời tiết": WEATHER_SURCHARGE
        },
        totalTripCost: Math.round(tongChuyen) + " VNĐ"
    };
});

// 3. BÁO CÁO TỔNG KẾT
let tietKiem = Math.round(tongGiaoLe - tongGop);
let msgRain = originalTrips[0] && originalTrips[0].isRaining ? "⚠️ Đà Nẵng đang mưa, hệ thống tự động cộng phụ phí thời tiết." : "☀️ Thời tiết đẹp, không có phụ phí rủi ro.";

// Tọa độ kho (Đà Nẵng): nếu có lat/lng thực mới tính pixel kho
let depotPx = null;
if (hasRealCoords) {
    depotPx = latLngToPixel(16.065, 108.215, allOrdersFlat, 280, 220, 20);
}

let finalResponse = {
    chatbot_message: `<b>Sếp ơi, em đã tối ưu xong!</b><br>${msgRain}<br>Gom thành công <b>${finalTrips.length} chuyến xe</b>.<br>🚀 Lộ trình đi giao đã được thuật toán AI sắp xếp lại ngắn nhất (Shipper không phải quay đầu).<br>💰 Thuật toán giúp sếp <b>TIẾT KIỆM ĐƯỢC ${tietKiem.toLocaleString('vi-VN')} VNĐ</b> so với giao lẻ!`,
    invoices: finalTrips,
    map_data: {
        depot: { id: "KHO", name: "KHO TỔNG", x: depotPx ? depotPx.x : null, y: depotPx ? depotPx.y : null },
        trips: mapTrips
    }
};

return [{ json: finalResponse }];

// Lấy dữ liệu Đầu vào và Thời tiết (Trường hợp 1 đơn vẫn có Thời tiết vì nó chạy qua API thời tiết rồi)
const rawData = $('Webhook').item.json.body;
const weatherData = $('HTTP Request1').item.json; 
const orders = rawData.orders || [];

// Kiểm tra thời tiết để "cà khịa"
const weatherId = weatherData.weather[0].id;
const isRaining = weatherId < 700;
let weatherMsg = isRaining ? "⛈️ Đà Nẵng đang mưa to, sếp nhớ boa thêm tiền cho anh em shipper nhé!" : "☀️ Trời đang nắng ráo, book một phát có xế ngay!";

let msg = "";

// Nếu Web ném sang mảng rỗng (0 đơn)
if (orders.length === 0) {
    msg = `<b>Sếp đùa em à?</b> 🤬<br>Chưa có đơn hàng nào mà bắt em chạy thuật toán tối ưu! Ném thêm đơn vào đây cho em làm việc!`;
} 
// Nếu Web ném sang đúng 1 đơn
else {
    msg = `<b>Báo cáo sếp: Không cần dùng Dao Mổ Trâu để giết Gà!</b> 🐓<br>Hệ thống phát hiện chỉ có vỏn vẹn <b>1 đơn hàng</b> (Mã: ${orders[0].id}).<br>Thuật toán gộp chuyến từ chối hoạt động vì không cần thiết. Đề xuất sếp book thẳng GrabExpress hoặc Ahamove cho nhanh gọn lẹ!<br><br><i>${weatherMsg}</i>`;
}

// Trả về JSON chuẩn form để Laravel không bị lỗi (Để mảng rỗng cho hóa đơn và bản đồ)
return [{
    json: {
        chatbot_message: msg,
        invoices: [], 
        map_data: {
            depot: { id: "KHO", name: "KHO TỔNG", x: 250, y: 250 },
            trips: []
        }
    }
}];
